"use client";

import React, { ReactNode } from "react";
import { Tab } from "@headlessui/react";

interface TabItem {
  label: string;
  content: ReactNode;
}

interface UltraQualityTabsProps {
  tabs: TabItem[];
}

function classNames(...classes: string[]) {
  return classes.filter(Boolean).join(" ");
}

export function UltraQualityTabs({ tabs }: UltraQualityTabsProps) {
  return (
    <div className="w-full max-w-3xl mx-auto">
      <Tab.Group>
        <Tab.List className="flex space-x-1 rounded-xl bg-gray-200 dark:bg-gray-700 p-1">
          {tabs.map((tab, idx) => (
            <Tab
              key={idx}
              className={({ selected }) =>
                classNames(
                  "w-full py-2.5 text-sm font-medium leading-5 text-gray-700 dark:text-gray-300 rounded-lg",
                  selected
                    ? "bg-white dark:bg-gray-800 shadow"
                    : "hover:bg-white/[0.12] dark:hover:bg-gray-600"
                )
              }
            >
              {tab.label}
            </Tab>
          ))}
        </Tab.List>
        <Tab.Panels className="mt-4">
          {tabs.map((tab, idx) => (
            <Tab.Panel
              key={idx}
              className="rounded-xl bg-white dark:bg-gray-800 p-4 shadow"
            >
              {tab.content}
            </Tab.Panel>
          ))}
        </Tab.Panels>
      </Tab.Group>
    </div>
  );
}
